import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"99A. Study Leave","description":"","frontmatter":{"title":"99A. Study Leave","eba":"Mental Health Services 2024-2028","topics":["leave","study-leave","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/education-pd/99A-study-leave.md","filePath":"ebas/mental-health/rpn-pen-mho/education-pd/99A-study-leave.md"}'),r={name:"ebas/mental-health/rpn-pen-mho/education-pd/99A-study-leave.md"};function i(s,e,l,p,d,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_99a-study-leave" tabindex="-1">99A. Study Leave <a class="header-anchor" href="#_99a-study-leave" aria-label="Permalink to &quot;99A. Study Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p>See <a href="/eba/ebas/mental-health/common-terms/preliminary/9-definitions.html">clause 9.1</a>(kk)- Relevant qualification/relevant component of qualification etc. for considerations relating to relevance</p><p><strong>99A.1</strong> Entitlement – RPN</p><p><strong>(a)</strong> Study Leave must only be used for research and/or studies in relation to a post- graduate course at a tertiary education institution which is relevant to a Mental Health Nursing role.</p><p><strong>(b)</strong> Paid study leave may be taken as mutually agreed by, for example, four hours per week, eight hours per fortnight or blocks of 38 hours at a residential school.</p><p><strong>(c)</strong> A part-time Employee will be entitled to paid study leave on a pro rata basis.</p><p><strong>(d)</strong> Leave pursuant to this clause does not accumulate from year to year.</p><p><strong>99A.2</strong> Entitlement - PEN</p><p><strong>(a)</strong> A Psychiatric Enrolled Nurse can access the entitlement at 99A.1 where they are undertaking a Bachelor of Nursing (however titled).</p><p><strong>(b)</strong> Subject to operational requirements, a PEN will be eligible to:</p><p><strong>(i)</strong> undertake post registration mental health modules</p><p><strong>(ii)</strong> undertake training in respect of which a qualifications allowance is payable</p><p><strong>(iii)</strong> receive two weeks leave to undertake clinical placements where they are enrolled in an undergraduate course of training leading to registration as a Registered Nurse.</p><p><strong>99A.3</strong> Application</p><p>An Employee wishing to take study leave must:</p><p><strong>(a)</strong> apply in writing to the Employer as early as possible prior to the proposed leave date; and</p><p><strong>(b)</strong> include with the application:</p><p><strong>(i)</strong> details of the course and institution in which the Employee is enrolled or proposes to enrol; and</p><p><strong>(ii)</strong> details of the relevance of the course to the Employee&#39;s employment.</p><p><strong>99A.4</strong> Response to application</p><p><strong>(a)</strong> The Employer will not unreasonably refuse a request for study leave.</p><p><strong>(b)</strong> The Employer must, within seven days of the application being made, notify the Employee in writing whether the application for study leave has been approved.</p><p><strong>99A.5</strong> Mental Health Nursing Scholarships - RPN</p><p><strong>(a)</strong> Subject to operational requirements and the number of Mental Health Nursing Scholarships funded by the Department outlined in (b) below, an Employee with a Mental Health Nursing Scholarship will be entitled to total paid study leave equivalent to 104 hours per annum.</p><p><strong>(b)</strong> A minimum of 1000 nurses will be eligible to receive study leave funded by the Department over the life of the Agreement.</p><p><strong>99A.6</strong> Transition Program – PEN Employers will provide 6-12 month transition program for Enrolled Nurses commencing in Mental Health in accordance with agreed funding arrangements. These funding arrangements will provide a 10 day transition program for 550 Enrolled Nurses across the sector.</p><p><strong>99A.7</strong> Advanced Diploma In Mental Health Nursing - PEN</p><p><strong>(a)</strong> Employers are encouraged to partner with a TAFE or RTO to provide the Advanced Diploma of Mental Health Nursing to current Enrolled Nurses.</p><p><strong>(b)</strong> The enrolled nurses must be enrolled in HLT64121 (or its successor) and complete the mental health units required in order to obtain the specialisation of Advanced Diploma in Mental Health Nursing.</p><p><strong>(c)</strong> The aim is for Enrolled Nurses to participate in further study while performing their clinical hours on site at their place of employment.</p><p><strong>(d)</strong> It is at the discretion of each Employer as to whether they participate in the Advanced Diploma in Mental Health Nursing Partnership.</p><p><strong>(e)</strong> The Employer will establish a working party comprising of the Unions, the Employer, participating TAFEs/RTOs and if practicable, the Department of Health. The working party will discuss implementation and evaluation of the Partnership.</p><p><strong>99A.8</strong> Staff Replacement</p><p>All absences arising from approved leave under clause 99A (study leave) will be backfilled in clinical areas where that Employee would ordinarily have a patient allocation.</p><p>Plain language terms: exam leave, education leave.</p>',36)])])}const g=t(r,[["render",i]]);export{c as __pageData,g as default};
